n = int(input())
s = input()


def draw(n, s):
    if n == 0:
        return
    i = 0
    while i < n:
        if s[i] == "]":
            print("|", end="")
            i += 1
        else:
            print("+", end="")
            i += 1
        for j in range(i, n):
            if s[j] == "]":
                print("-", end="")
            else:
                print("+", end="")
        print()
    print()
    draw(i, s)
    draw(n - i, s)


draw(n, s)
